{
  "name": "Healthy Connections Medicaid",
  "eligibility": {
    "age": 65,
    "income_limits": "For elderly (65+), eligibility for long-term care programs requires income under $2,982 per month for a single applicant in 2026; general Medicaid for aged, blind, or disabled has no specific dollar table by household size in sources, but parents/caretakers up to 100% FPL, children up to 213% FPL (with 5% disregard). Income from jobs, SSI, etc., is considered.[2][5]",
    "asset_limits": "For long-term care (e.g., nursing home), countable assets under $2,000 for a single applicant; includes checking/savings accounts and other resources owned. Exemptions not detailed in sources, but standard Medicaid planning applies (e.g., primary home may be exempt in some cases).[3][5]",
    "other_requirements": ["Blind, totally/permanently disabled, or nursing facility level of care (NFLOC) for long-term care; functional need for ADLs; pregnant, under 19, parent/caretaker of child under 18, or foster/adopted child also qualify under broader categories; must apply to confirm."[1][3][5]]
  },
  "benefits": {
    "type": "service",
    "value": "Pays for medical bills, nursing facility care, other medical expenses for those 65+ or disabled; long-term care services if NFLOC met; managed care plans with mandatory enrollment after eligibility; specific services not itemized by dollar/hour but include doctor visits, hospital care via enrolled plans.[1][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.scdhhs.gov/how-to-apply or apply.scdhhs.gov", "Phone: 1-888-549-0820 (TTY: 888-842-3620)", "Mail: Request paper application by calling 888-549-0820", "In-person: Local county office or authorized hospitals/Family Health Centers (e.g., call 803-531-6900)"],
    "processing_time": "Up to 45 days generally; 90 days if disability determination needed.[1][6]",
    "waitlist": "Not mentioned in sources; may vary by long-term care demand.[5]",
    "forms": ["Online application tool at apply.scdhhs.gov; no specific form name/number listed."],
    "documents": ["Date of birth, Social Security Number, income from jobs/training, benefits (SSI, VA, child support), checking/savings/resources amounts, rent/mortgage/utilities, health coverage/medical payments for all household members.[3][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide.",
    "regional_variations": "Processing times may vary by region or applicant category; apply at local county offices, but no specific provider/wait differences detailed.[6]",
    "offices_or_providers": ["Local county offices; Family Health Centers (e.g., 803-531-6900); managed care plans like Absolute Total Care.[3][7]"]
  },
  "official_source": "https://www.scdhhs.gov/how-to-apply",
  "gotchas": ["Must enroll in managed care plan (90-day switch window, then restricted); apply directly to SC Healthy Connections, not Marketplace for final determination; long-term care needs NFLOC, not just age/income; eligibility reviewed annually; hospitals can't always deem eligibility unless authorized; no ACA expansion, so limited parent coverage.[2][4][5][6]"],
  "data_shape_notes": "Elderly focus on long-term care with strict $2,982 income/$2,000 asset for singles; mandatory managed care enrollment post-eligibility; varies by care need (NFLOC/ADL) rather than household size for seniors."
}

{
  "name": "SHIP / I-Care",
  "eligibility": {
    "age": 65,
    "income_limits": "No income limits; open to all Medicare-eligible individuals. Medicare eligibility requires age 65 or older, or under 65 with certain disabilities.[4][2]",
    "asset_limits": "No asset limits or tests apply.[4]",
    "other_requirements": ["Must be eligible for Medicare (age 65+, or under 65 with disabilities)", "South Carolina resident", "Available to beneficiaries, families, or caregivers[2][4]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free personalized health insurance counseling on Medicare and Medicaid options, including plan comparisons, enrollment assistance, prescription assistance review, bill problem resolution, and referrals. Services include help with Medicare health/drug plans, supplements, Medigap, and understanding coverage changes.[2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-868-9095[7]", "In-person or contact local providers like Lt. Governor’s Office on Aging at 1301 Gervais Street, Suite 350, Columbia SC 29201[6]", "Local SHIP counselors via area agencies (e.g., Appalachian Area Agency on Aging, CareSouth Carolina locations)[2][5]"],
    "processing_time": "Immediate counseling upon contact; no formal processing as it's not an entitlement program[2][4]",
    "waitlist": null,
    "forms": ["SHIP Medicare Worksheet (downloadable from local providers like scacog.org)[2]"],
    "documents": ["Medicare card", "Medicare Summary Notice (MSN) or bills if resolving issues", "List of current medications and insurance details for plan comparisons[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered through local area agencies on aging and providers (e.g., CareSouth Carolina in Hartsville, Chesterfield; Appalachian Area Agency), with varying office hours and locations, but uniform statewide service model[2][5]",
    "offices_or_providers": ["Lt. Governor’s Office on Aging, 1301 Gervais Street, Suite 350, Columbia SC 29201[6]", "Local contacts via 1-800-868-9095[7]"]
  },
  "official_source": "https://www.shiphelp.org/ships/south-carolina/[7]",
  "gotchas": ["Not a direct service or financial benefit program—provides counseling and referrals only, not healthcare or payments[4]", "Does not cover non-medical personal care like bathing/dressing[4]", "Plans change annually; counseling recommended during Open Enrollment (Oct 15-Dec 7)[4]", "Funded federally, independent of insurance companies[2]"],
  "data_shape_notes": "Counseling-only program with no financial eligibility tests; delivered via statewide network of local counselors and agencies"
}

{
  "name": "Legal Assistance for Seniors",
  "eligibility": {
