    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging via GetCareSC.com using ZIP code to find services[2]", "SC Bar Pro Bono Program at (803) 799-6653 for volunteer attorney participation and referrals[1]", "South Carolina Legal Services intake: call 1-888-346-5592 or apply online at sclegal.org[7]", "Regional providers such as Santee-Lynches Regional Council of Governments for referrals[4]"],
    "processing_time": "For SC Legal Services, hear from local office within 5-7 business days after application[7]; no statewide processing time specified.",
    "waitlist": "Not mentioned; may vary by local provider.",
    "forms": ["Online application via sclegal.org for SC Legal Services; no specific statewide form name/number identified[7]"],
    "documents": ["Not explicitly listed; typically income verification and details of legal problem for eligibility screening, as eligibility depends on income and problem type[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide through Area Agencies on Aging, with priority to low-income, minority, limited English, and rural areas[1]",
    "regional_variations": "Programs vary by county; services delivered through various local Area Agencies on Aging with different providers and partnerships; use ZIP code on GetCareSC.com for local access[2]",
    "offices_or_providers": ["Area Agencies on Aging throughout the state[1]", "SC Bar Pro Bono Program[1]", "SC Legal Services statewide offices[5]", "Santee-Lynches Regional Council of Governments (regional example)[4]"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/legal-assistance-older-adults",
  "gotchas": ["Not direct application to state agency; must go through local Area Agencies on Aging or partners like SC Legal Services[1][2]", "Prioritizes 'greatest economic or social need'—not automatic for all 60+; competition for limited funds[1]", "Services are free but capacity-limited (e.g., 1,160 cases/year statewide)[1]", "Varies significantly by county/provider; check GetCareSC.com for local availability[2]", "SC Legal Services has separate income-based eligibility[5][7]"],
  "data_shape_notes": "Delivered statewide via decentralized local Area Agencies on Aging with varying providers per county/region; no fixed income/asset tables published; priority-based rather than strict cutoffs; funding and case volume tracked annually but not individualized"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to anyone regardless of financial status.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Resident must be in a long-term care facility (nursing homes, assisted living, community residential care facilities, DDSN or DMH facilities) in South Carolina.", "Complaint must relate to quality of care, quality of life, residents' rights, abuse/neglect/exploitation, improper transfers/discharges, or benefits assistance.", "Available to residents, family, friends, facility staff, or any concerned community member filing on behalf of a resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints; advocacy for residents' rights; assistance with appeals/grievances; education on resident rights and benefits; mediation with facilities; information/referrals on long-term care; promotion of dignity, respect, and quality of care/life. No financial aid, hours, or dollar amounts provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide toll-free 1-800-868-9095 (for abuse/neglect or general complaints)[1]", "Phone/Email: Regional offices (e.g., Santee-Lynches: 803-774-1983 or sbrooks@slcog.org[2][4]; Appalachian: 864-242-9733 or ombudintake@scacog.org[3])", "In-person/Walk-in: Regional offices", "Email or outreach events via regional providers"],
    "processing_time": "Not specified; ombudsmen investigate promptly and follow up to ensure resolution.",
    "waitlist": null,
    "forms": ["No specific forms required; complaints filed via phone, email, or in-person."],
    "documents": ["No documents needed; provide details of the complaint verbally or in writing. Confidentiality protected unless permission given."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of long-term care facilities; administered statewide through 10 regional offices covering specific counties (e.g., Santee-Lynches: Clarendon, Lee, Kershaw, Sumter[2][4]; Appalachian: Anderson, Cherokee, Greenville, Oconee, Pickens, Spartanburg[3]).",
    "regional_variations": "Services delivered via 10 regional offices with local contacts, phone numbers, and managers; contact methods and coverage areas differ by region but core services consistent statewide.",
    "offices_or_providers": ["State office: South Carolina Department on Aging, 1301 Gervais Street, Suite 350, Columbia, SC 29201 (803-734-9900)[1][6]", "10 regional offices (examples: Santee-Lynches Regional Council of Governments[2][4], Appalachian Council of Governments[3])"]
  },
  "official_source": "https://aging.sc.gov/programs-initiatives/long-term-care-ombudsman-program",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy for complaints in facilities; does not provide direct services like care or payments.", "Only for long-term care facility residents, not community-dwelling adults (separate reporting for community abuse).", "Complaints handled confidentially, but identity may need disclosure for resolution (resident chooses).", "Anyone can file, but focus is protecting facility residents."],
  "data_shape_notes": "no income/asset/age test; advocacy-only for LTC facility residents; delivered via 10 regional offices with local contacts; free statewide service under Older Americans Act."
}

{
  "name": "Vantage Point",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits stated in available sources; services prioritize highest need via assessment scoring, often targeting low-income seniors. Financial eligibility assessed case-by-case for programs like vouchers ($25 value for Senior Farmers Market Nutrition Program, first-come first-served).",
    "asset_limits": "No asset limits specified.",
    "other_requirements": ["Resident of Pee Dee region (Chesterfield, Darlington, Dillon, Florence, Marion, Marlboro counties)", "Assessed need via Question Pro tool for priority tier", "Reassessed annually"]
  },
  "benefits": {
    "type": "service",
    "value": "Information and referral; advocacy for entitlements; insurance counseling (Medicare, Medicaid, long-term care via I-CARE); caregiver support; respite care; meals (home-delivered/non-perishable via partners); Senior Farmers Market Nutrition vouchers ($25 coupons June-Oct); mobility/housing assistance; supplemental services on limited basis; helps maintain independence at home.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: (843) 857-0111 (Hartsville office), 843-383-8632 or toll-free 866-505-3331 (I-CARE)", "In-person: 640 South Fourth Street, PO Box 999, Hartsville, SC 29551", "Contact local Council on Aging for meals/services"],
    "processing_time": "Not specified; referrals made as service openings available.",
    "waitlist": "Yes, maintained by Assessment Coordinator when demand exceeds funding; priority by electronic tier score.",
    "forms": ["Question Pro Assessment (used for priority scoring)"],
    "documents": ["Not explicitly listed; prepare income/asset proof for financial aid screening, ID for residency verification"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Pee Dee region: Chesterfield, Darlington, Dillon, Florence, Marion, Marlboro counties",
    "regional_variations": "Operates as Area Agency on Aging (AAA) specific to Pee Dee; partners with local Councils on Aging for services like meals; staff shortages noted as barrier in Pee Dee.",
    "offices_or_providers": ["Hartsville main office (640 South Fourth Street, PO Box 999, Hartsville, SC 29551)", "Division of CareSouth Carolina (FQHC and ADRC)", "Local Councils on Aging for meals/referrals"]
  },
  "official_source": "https://www.caresouth-carolina.com/seniors",
  "gotchas": ["Not statewide—limited to 6 Pee Dee counties; heavy waitlists due to funding limits and staff shortages; priority-based (highest score first), not first-come; separate veteran program exists but unrelated to elderly family services; voucher programs exhaust supply quickly."],
  "data_shape_notes": "Region-restricted AAA with priority tiers via assessment tool; services limited by funding/openings; partners with Councils on Aging; no fixed income/asset tables, need-based scoring."
}

{
  "name": "Senior Medicare Patrol",
  "eligibility": {
    "age": null,
