    "asset_limits": "No asset limits; not applicable[1][2]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver suspecting or needing help with Medicare fraud, errors, or abuse[1][2][5]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Outreach and education via presentations, community events, and one-on-one support; counseling to review Medicare Summary Notices (MSNs) for errors; investigation of complaints and referrals to state/federal agencies (e.g., HHS OIG, CMS); volunteer assistance to prevent, detect, and report fraud, errors, abuse[1][2][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: South Carolina Department on Aging at 1-800-868-9095[1]", "Contact local Area Agency on Aging[1]", "Phone: Medicare/Medicaid Fraud Hotline at 1-800-447-8477[4]", "Local SMP via agencies like AOASCC or 1-800-994-9422[6]"],
    "processing_time": "No formal application or processing time; immediate counseling and referral assistance available upon contact[1][2]",
    "waitlist": null,
    "forms": ["No specific forms required; may involve reviewing Medicare Summary Notice (MSN)[6][7]"],
    "documents": ["Medicare Summary Notice (MSN), billing statements, or details of suspected fraud for review[6][7]"]
